INSERT INTO `product` VALUES ('0130a681-5e53-49da-bccb-d650580f5200','Mango','Áo choàng ngủ từ chất liệu nỉ bông polyester siêu dày dặn và ấm áp, phụ kiện hoàn hảo cho buổi sáng mùa đông.',950000,950000,'Áo Choàng Ngủ Nỉ Bông','90ba2165-1211-44d6-94fb-2cfd0a6ade61'),('026b8f7b-9d62-406d-b4b5-ad0766a5feda','Gucci','Gọng kim loại siêu nhẹ chống gỉ, tròng kính từ polycarbonate chống tia UV tuyệt đối cho chuyến du lịch nắng gắt.',4250000,4250000,'Kính Mát Phi Công','eb0f9468-f640-4ac3-85dd-fc1618d01e87'),('037864ea-1fc9-4a98-ad96-73c7031b4b64','Puma','Áo thun ba lỗ khoét sâu nách giúp vận động tay linh hoạt từ vải lưới polyester thoáng khí tuyệt đối.',450000,450000,'Áo Tanktop Tập Gym Nam','52ca35f3-79af-4540-a81d-9b02c9ff7e82'),('06b0c255-6c1c-4fd6-82c0-d88f3eba7d40','Charles & Keith','Túi xách phom hộp cứng cáp từ da tổng hợp, quai đeo xích phối da sang trọng cho các vật dụng cá nhân nhỏ gọn.',1850000,1850000,'Túi Xách Đeo Chéo Mini','eb0f9468-f640-4ac3-85dd-fc1618d01e87'),('074216a9-62ef-4297-bfc4-56358f0c75b4','Uniqlo','Bộ đồ ngủ từ chất liệu nỉ bông polyester dày, giữ ấm tuyệt đối cho những đêm đông giá rét.',850000,850000,'Bộ Đồ Nỉ Ngủ Mùa Đông','90ba2165-1211-44d6-94fb-2cfd0a6ade61'),('074af4fa-2373-4594-af09-4635672caa84','Nike','Bộ trang phục từ vải thun poly interlock co giãn, công nghệ Dri-FIT giúp thoát mồ hôi cực nhanh cho vận động viên.',1450000,1450000,'Bộ Đồ Tập Gym Pro','52ca35f3-79af-4540-a81d-9b02c9ff7e82'),('0fbd50af-473d-4715-9941-0b33bab46bf9','Uniqlo','Áo khoác hoodie có khóa kéo, chất liệu nỉ bông dày dặn lót lông cừu nhân tạo siêu ấm, thích hợp mặc ở nhà hoặc đi dạo.',650000,650000,'Áo Hoodie Zip Nỉ Chần','3b5cd899-246e-4dd7-a253-f5c612530bfc'),('10b7acf8-0eb8-41d2-95ef-7020759d7f92','Zara','Áo thun 100% cotton in hình nghệ thuật hiện đại, màu sắc nổi bật, phong cách trẻ trung cho thanh niên.',450000,450000,'Áo Thun In Họa Tiết','61f1088e-d5a3-4013-81ee-86b70cec3098'),('141187aa-eb73-43a2-9be3-afa93b962c46','Adidas','Bộ trang phục nỉ dày dặn giữ nhiệt chuyên dụng từ sợi bông fleece cho vận động viên tập luyện ngoài trời.',2450000,2450000,'Bộ Đồ Nỉ Tập Mùa Đông','52ca35f3-79af-4540-a81d-9b02c9ff7e82'),('170aa39b-76d9-4e17-9f00-2648e0c28deb','Gucci','Váy dài xếp ly thanh lịch với chất liệu tổng hợp Monogram đặc trưng, thắt lưng tinh tế tôn lên vòng eo người mặc.',5400000,5400000,'Váy Xếp Ly Công Sở','29347f9b-4b04-4aad-b116-fc54d47fe735'),('1be52253-b6ef-45b2-a2f7-d61db657675b','Mango','Váy dáng suông in họa tiết trừu tượng từ vải lanh thoáng mát, lý tưởng cho kỳ nghỉ hè dạo biển.',790000,790000,'Váy Suông In Họa Tiết','29347f9b-4b04-4aad-b116-fc54d47fe735'),('1c40add2-800c-427a-be75-6ccdb4fcacf4','Uniqlo','Bộ pijama thun cotton 100% in hình dễ thương, co giãn tốt, mang lại sự thoải mái tối đa cho giấc ngủ.',450000,450000,'Bộ Pijama Thun Cotton In Hình','90ba2165-1211-44d6-94fb-2cfd0a6ade61'),('1d6424bc-fff7-47d8-8426-8b3f7996b6f6','Nike','Áo bra hỗ trợ cường độ cao từ vải nỉ nén co giãn, thiết kế lưng chữ X giúp cố định tối ưu khi vận động mạnh.',950000,950000,'Áo Bra Thể Thao Support','52ca35f3-79af-4540-a81d-9b02c9ff7e82'),('2086653f-e611-43e3-8987-f69ef03918d8','Mango','Váy ren thêu tỉ mỉ dáng đuôi cá điệu đà trên nền vải polyester cao cấp, mang đến vẻ đẹp cổ điển và nữ tính tuyệt đối.',1650000,1650000,'Váy Ren Đuôi Cá','29347f9b-4b04-4aad-b116-fc54d47fe735'),('216026f4-0b10-44ca-a43c-f2890ae8ce8d','H&M','Áo polo thun cá sấu từ sợi cotton piqué bền bỉ, phom dáng chuẩn, mang lại sự lịch lãm đầy năng động cho công sở.',1200000,1200000,'Áo Polo Piqué Cổ Điển','61f1088e-d5a3-4013-81ee-86b70cec3098'),('227faf47-5743-4e03-93d8-2c4747531837','H&M','Quần jogger chất nỉ bông polyester ấm áp, gấu quần bo thun chắc chắn, thích hợp cho tập luyện hoặc mặc ở nhà.',550000,550000,'Quần Jogger Nỉ Basic','3e9d83d9-4aaf-4e42-9ca0-fda5fce8935f'),('24e9a912-602e-43c6-a5a2-c114a67ee4e9','Adidas','Công nghệ đệm Boost hoàn trả năng lượng cực tốt, thân giày vải Primeknit ôm sát như đi tất cho vận động viên.',4500000,4500000,'Giày Chạy Bộ Ultraboost','a2d4d2d5-76f0-4fe8-a01c-19a4818925a5'),('2507eba4-3aa7-460a-b2c8-fafb0e76833e','Uniqlo','Áo khoác len cardigan mềm mại từ sợi wool merino, các chi tiết thêu tay tinh xảo, cổ chữ V sâu dễ dàng phối đồ.',1150000,1150000,'Áo Cardigan Len Thêu','3b5cd899-246e-4dd7-a253-f5c612530bfc'),('2823b9f8-a827-4248-adec-433738bcece3','Uniqlo','Mũ len ôm đầu mềm mại từ sợi wool pha acrylic, giữ ấm tai hiệu quả, đơn giản dễ phối đồ hàng ngày.',350000,350000,'Mũ Beanie Dệt Kim','eb0f9468-f640-4ac3-85dd-fc1618d01e87'),('2dfea698-16a7-40dd-ae9d-d879052059a9','Uniqlo','Chất liệu nỉ flanel mỏng mềm mại từ cotton nguyên chất, họa tiết kẻ caro cổ điển, phù hợp khoác nhẹ bên ngoài.',690000,690000,'Áo Sơ Mi Flanel Kẻ Ô','61f1088e-d5a3-4013-81ee-86b70cec3098'),('30c4b7eb-2366-462e-be69-379778fedd7a','Adidas','Mũ lưỡi trai từ vải cotton thoáng khí, quai cài tùy chỉnh kích thước phía sau, thêu logo nổi bật cho phong cách năng động.',450000,450000,'Mũ Lưỡi Trai Logo Thêu','eb0f9468-f640-4ac3-85dd-fc1618d01e87'),('31599107-c54b-4a92-9c91-44d5e1ad7581','Levi\'s','Quần đùi jean từ denim 100% cotton với các chi tiết mài rách bụi bặm, gấu quần tua rua, phong cách trẻ trung.',950000,950000,'Quần Short Jean Rách','3e9d83d9-4aaf-4e42-9ca0-fda5fce8935f'),('34515573-0f8e-4385-9c2d-666d23857d7e','The North Face','Áo phao nhồi lông vũ tự nhiên, khả năng giữ nhiệt tuyệt đối cho khí hậu đại hàn, lớp vỏ ngoài polyester chống thấm.',3500000,3500000,'Áo Phao Lông Vũ','3b5cd899-246e-4dd7-a253-f5c612530bfc'),('38c10fae-c326-4117-a9f1-438c47086a1b','Levi\'s','Áo sơ mi vải denim bền bỉ từ 100% cotton, phong cách cao bồi, có thể mặc riêng hoặc khoác hờ ngoài áo thun trắng.',1450000,1450000,'Áo Sơ Mi Denim Bụi Bặm','61f1088e-d5a3-4013-81ee-86b70cec3098'),('399bce69-4451-44b7-87de-a9d0418a0764','Adidas','Áo khoác gió từ 100% tái chế polyester, tích hợp phản quang giúp an toàn khi chạy bộ ban đêm, phom áo khí động học.',1200000,1200000,'Áo Khoác Chạy Bộ Gió','52ca35f3-79af-4540-a81d-9b02c9ff7e82'),('3c39f920-ffe0-4de9-8f20-027482893586','Nike','Đôi giày huyền thoại từ da tổng hợp bền bỉ, đế đệm Air êm ái, thiết kế trắng sạch dễ phối đồ hàng ngày.',2850000,2850000,'Giày Sneaker Air Force 1','a2d4d2d5-76f0-4fe8-a01c-19a4818925a5'),('3c9c04f1-7bed-404a-b52c-4230cbdbd222','Zara','Áo choàng ngoài từ lụa satin kèm đai thắt, chất liệu mềm mại tạo cảm giác thư giãn tuyệt đối sau khi tắm.',850000,850000,'Áo Choàng Ngủ Silk','90ba2165-1211-44d6-94fb-2cfd0a6ade61'),('3fcfcd86-09b9-4adc-ba2e-7aed0de83155','Nike','Đế bánh mì độn cao 5cm từ cao su non giúp tăng chiều cao, chất liệu da tổng hợp trắng kem nữ tính.',3100000,3100000,'Giày Sneaker Platform Nữ','a2d4d2d5-76f0-4fe8-a01c-19a4818925a5'),('420ab440-0b24-4474-a6f4-1afcda3086f7','Zara','Áo sơ mi lụa satin với độ bóng sang trọng, thiết kế cổ đức truyền thống mang lại vẻ ngoài thanh lịch cho phái nữ.',850000,850000,'Áo Sơ Mi Silk Satin','61f1088e-d5a3-4013-81ee-86b70cec3098'),('4bbc30ee-4c94-49a0-9186-05ea12088be2','Mango','Khăn choàng dệt từ sợi cashmere siêu mềm mại và ấm áp từ tự nhiên, phụ kiện hoàn hảo cho mùa đông giá lạnh.',950000,950000,'Khăn Choàng Len Cashmere','eb0f9468-f640-4ac3-85dd-fc1618d01e87'),('4dad08a3-f67a-4a80-bee9-0e2976850458','Charles & Keith','Sandal quai mảnh từ da tổng hợp mềm, quai cổ chân tùy chỉnh, đế bệt thoải mái cho dạo phố mùa hè.',950000,950000,'Giày Sandal Dây Mảnh','a2d4d2d5-76f0-4fe8-a01c-19a4818925a5'),('4e97e93b-2baa-4748-9da3-4dad15c8dd89','Zara','Áo len cổ lọ dệt kim từ sợi len lông cừu merino giữ nhiệt tốt, phom dáng slim-fit sang trọng cho mùa đông.',1250000,1250000,'Áo Len Cổ Lọ Wool','61f1088e-d5a3-4013-81ee-86b70cec3098'),('4eb5878c-d9e2-4b86-b5f9-74a03565ef3d','H&M','Váy dáng suông chất liệu cotton 100% thoáng mát, thấm hút mồ hôi tốt, lý tưởng cho trang phục mặc hàng ngày.',450000,450000,'Váy Suông Cotton Basic','29347f9b-4b04-4aad-b116-fc54d47fe735'),('51ca4cc3-51a4-4632-a2c8-2050885eef43','Puma','Chất liệu vải microfiber mềm mượt như da thứ hai, độ co giãn cực đại giúp thực hiện các tư thế yoga khó nhất.',1250000,1250000,'Quần Tập Yoga Lưng Cao','52ca35f3-79af-4540-a81d-9b02c9ff7e82'),('534c5615-a598-4d81-bd11-8c49051f7dad','Charles & Keith','Sandal cao gót với quai trong suốt từ nhựa dẻo TPU, đế cao 5cm chắc chắn, phong cách hiện đại cho các buổi tiệc.',1350000,1350000,'Giày Sandal Cao Gót Quai Trong','a2d4d2d5-76f0-4fe8-a01c-19a4818925a5'),('5fc30db7-940f-4452-8316-850813881ecd','Mango','Bộ đồ ngủ pijama chất liệu lụa satin mướt mịn, họa tiết viền túi tinh tế, mang lại giấc ngủ trọn vẹn và êm ái.',1150000,1150000,'Bộ Pijama Lụa Sang Trọng','90ba2165-1211-44d6-94fb-2cfd0a6ade61'),('62e2446f-e4c9-412f-bc16-eed406cf94c1','Nike','Túi đựng đồ tập dung tích lớn từ vải dù nylon chống thấm, ngăn đựng giày riêng biệt cho người tập gym.',950000,950000,'Túi Trống Thể Thao Gym','52ca35f3-79af-4540-a81d-9b02c9ff7e82'),('6658b6e2-36f0-432b-b570-37c4078139ef','Puma','Quần short thể thao 2 lớp tích hợp quần lót ôm sát bên trong từ thun lạnh, túi khóa zip tiện lợi đựng điện thoại.',750000,750000,'Quần Short Tập Gym Nam','52ca35f3-79af-4540-a81d-9b02c9ff7e82'),('66d4b114-cbfd-4e2e-93a3-4f12209aac3a','Zara','Váy hoa nhí dáng xòe nhẹ nhàng, chất liệu voan mềm mại có lớp lót, phù hợp cho các buổi dạo phố hoặc hẹn hò.',850000,850000,'Váy Hoa Nhí Vintage','29347f9b-4b04-4aad-b116-fc54d47fe735'),('6c10301e-0250-4613-8fb5-dd62513ee8c0','Zara','Váy maxi dài chấm gót với họa tiết nhiệt đới, chất liệu chiffon bay bổng cho những chuyến du lịch biển mùa hè.',990000,990000,'Váy Maxi Đi Biển','29347f9b-4b04-4aad-b116-fc54d47fe735'),('6c19981c-9524-4db8-96f8-8c9fee18c741','dgfggggggggggggg','gdfgdfggggggg',0.1,0.1,'ầdgdghffjgjg','90ba2165-1211-44d6-94fb-2cfd0a6ade61'),('6cecfe6c-792f-4291-80bb-607d3b170822','Adidas','Thiết kế sneaker phom thấp từ da bò thật phối da lộn, đế đệm bằng cao su dẻo, mang đậm nét cổ điển cho đi chơi.',3150000,3150000,'Giày Sneaker Forum Low','a2d4d2d5-76f0-4fe8-a01c-19a4818925a5'),('6d717707-5bfb-412e-a01b-0c2832d1e871','Uniqlo','Áo khoác denim chất liệu bò 100% cotton bền đẹp theo thời gian, phong cách bụi bặm, dễ phối đồ tầng lớp (layering).',1650000,1650000,'Áo Khoác Denim Classic','3b5cd899-246e-4dd7-a253-f5c612530bfc'),('7096c319-a0ca-4e10-b874-63995ea1b783','Adidas','Thiết kế trắng tối giản từ da bò thật cao cấp, biểu tượng 3 sọc đục lỗ, phù hợp cho mọi lứa tuổi đi học đi làm.',2650000,2650000,'Giày Stan Smith Classic','a2d4d2d5-76f0-4fe8-a01c-19a4818925a5'),('70d6c548-41e5-488c-bfd5-7d5fab6df89b','Zara','Áo khoác dáng dài từ vải gabardine chống thấm nước nhẹ, thiết kế cổ điển với hàng cúc kép, biểu tượng của sự thanh lịch.',3200000,3200000,'Áo Khoác Trench Coat','3b5cd899-246e-4dd7-a253-f5c612530bfc'),('70eb3cf5-e724-4480-9667-b1fff386d02b','Levi\'s','Dáng quần ôm vừa vặn từ hông xuống cổ chân, chất liệu denim 98% cotton co giãn giúp cử động thoải mái.',1850000,1850000,'Quần Jean Slim Fit 511','3e9d83d9-4aaf-4e42-9ca0-fda5fce8935f'),('783c2f99-648a-4501-997b-0838b38e1fbb','Nike','Quần short chạy bộ siêu nhẹ từ vải dù micro-fiber, có lớp lót trong khô nhanh và túi chìa khóa ẩn.',690000,690000,'Quần Short Chạy Bộ Nam','52ca35f3-79af-4540-a81d-9b02c9ff7e82'),('78dd7467-7195-4bb8-af26-8cef94ed93e1','Zara','Kiểu dáng váy ngắn vải dạ tweed dày dặn, phối nút đồng nổi bật, mang lại vẻ ngoài cổ điển và quý phái.',1850000,1850000,'Váy Dạ Tweed Sang Chảnh','29347f9b-4b04-4aad-b116-fc54d47fe735'),('7ce01824-94db-4c0e-9550-0a6dcce54906','Uniqlo','Áo sơ mi vải oxford dệt dày dặn từ 100% cotton, phom dáng slim-fit truyền thống phù hợp cho mọi hoàn cảnh.',490000,490000,'Áo Sơ Mi Cotton Oxford','61f1088e-d5a3-4013-81ee-86b70cec3098'),('80e11e7f-cc8b-40da-b600-dab315612a3e','Uniqlo','Áo khoác gió siêu nhẹ làm từ 100% nylon, chống thấm nước và cản gió tốt, có thể gấp gọn trong túi tiện lợi khi đi du lịch.',790000,790000,'Áo Khoác Gió Ultra Light','3b5cd899-246e-4dd7-a253-f5c612530bfc'),('83cb5550-1bdf-464c-b0e4-9b4d1c27a802','Charles & Keith','Thiết kế giày gót nhọn cổ điển từ da PU cao cấp bóng nhẹ, độ ca